_DISK_BLOB_MAGIC = b"DSPC"
_CODEC_NONE = 0x00
_CODEC_GZIP = 0x01
_CODEC_ZLIB = 0x02
_CODEC_BY_NAME = {None: _CODEC_NONE, "gzip": _CODEC_GZIP, "zlib": _CODEC_ZLIB}


class _CacheNamespaceAccessor:
    """Proxy returned by `Cache.namespace` that supports get/set/call usage.

    This lets a single attribute serve three call patterns required by the API:
    `dspy.cache.namespace` (read current value), `dspy.cache.namespace = "x"` (set current
    value, handled by the property setter), and `with dspy.cache.namespace("x"):` (temporarily
    scope the namespace).
    """

    __slots__ = ("_cache",)

    def __init__(self, cache: "Cache"):
        self._cache = cache

    def __call__(self, namespace: Optional[str] = None) -> ContextManager:
        return self._cache._namespace_context(namespace)

    def __eq__(self, other):
        return self._cache.get_namespace() == other

    def __ne__(self, other):
        return not self.__eq__(other)

    def __hash__(self):
        return hash(self._cache.get_namespace())

    def __bool__(self):
        return bool(self._cache.get_namespace())

    def __repr__(self):
        return repr(self._cache.get_namespace())

    def __str__(self):
        return str(self._cache.get_namespace())


